def fibonacci(n):
    if n < 2:
        return n
    return fibonacci(n-1) + fibonacci(n-2)

def decorator_factory(prefix):
    def decorator(func):
        def wrapper(*args, **kwargs):
            print(f'{prefix}: calling {func.__name__}')
            return func(*args, **kwargs)
        return wrapper
    return decorator

from dataclasses import dataclass

