def get_primes(n):
    sieve = [True] * n
    for p in range(2, n):
        if sieve[p]:
            yield p
            for i in range(p*p, n, p):
                sieve[i] = False

class Singleton:
    _instance = None
    def __new__(cls):
        if cls._instance is None:
            cls._instance = super(Singleton, cls).__new__(cls)
        return cls._instance

def fibonacci_generator():
    a, b = 0, 1
    while True:
        yield a
        a, b = b, a + b

