WITH RankedEmployees AS (
  SELECT Id, Name, Salary, ROW_NUMBER() OVER(PARTITION BY DepartmentId ORDER BY Salary DESC) as Rank
  FROM Employees
)
SELECT * FROM RankedEmployees WHERE Rank = 1;

CREATE TRIGGER trg_AfterInsert ON Users
AFTER INSERT
AS
BEGIN
  INSERT INTO AuditLog (UserId, Action) SELECT Id, 'CREATED' FROM inserted;
END;

WITH RankedSales AS (
    SELECT id, amount, ROW_NUMBER() OVER (ORDER BY amount DESC) as rnk
    FROM sales_records
)
SELECT id, amount FROM RankedSales
WHERE rnk <= 5;

